{
  "command": "python generate_service.py --name myapp --exec /usr/bin/myapp --user www-data --description 'My Application' --after network.target --restart on-failure --output myapp.service && cat myapp.service",
  "description": "Test generate_service.py with example args"
}

{
  "command": "python generate_service.py --name testapp --exec /usr/bin/testapp --after network.target --after syslog.target --env PORT=8080 --env DEBUG=false --working-dir /var/lib/testapp --output test.service && cat test.service",
  "description": "Test with multiple after/env and working-dir"
}

{
  "command": "python generate_service.py --name minimal --exec /usr/bin/minimal --output minimal.service && cat minimal.service",
  "description": "Test with only required args"
}

{
  "command": "python generate_service.py --name test --exec /usr/bin/test --env INVALIDFORMAT 2>&1; echo \"Exit code: $?\"",
  "description": "Test invalid env format error handling"
}

{
  "command": "rm -f myapp.service test.service minimal.service",
  "description": "Clean up test service files"
}
